class Solution:
    def leftRightDifference(self, nums):
        n = len(nums)
        res = []
        for i in range(n):
            left_sum = sum(nums[:i])
            right_sum = sum(nums[i + 1:])
            res.append(abs(left_sum - right_sum))
        return res

