var leftRightDifference = function(nums) {
    const total = nums.reduce((a, b) => a + b, 0);
    let left = 0;
    const res = [];
    for (const v of nums) {
        const right = total - left - v;
        res.push(Math.abs(left - right));
        left += v;
    }
    return res;
};
